sys_script_include.script:
function IsValidTable(strTable,bNoCache)
{
	strTable = GetStringValue(strTable);
	if (strTable.trim() != strTable)
	{
		return false;
	}

	var bResult = null;

	if (bNoCache == false)
	{
		var cache = new TransactionCacheAPI('DEVTOOLS');
		bResult = cache.GetItem('IsValidTable_'+strTable);
		if (bResult != null)
		{
			return bResult;
		}
	}	

	bResult = RunScriptInGlobalScope(
		'var tableUtils = new TableUtils(param1);result = tableUtils.tableExists();',
		strTable);

	if (bNoCache == false)
	{
		cache.SetItem('IsValidTable_'+strTable,bResult);
	}
	return bResult;
}
